/** Recursively convert null values to undefined */
export type NullToUndefined<T> = T extends null ? undefined : T extends (infer U)[] ? NullToUndefined<U>[] : T extends object ? {
    [K in keyof T]: NullToUndefined<T[K]>;
} : T;
export declare function nullToUndefined<T>(obj: T): NullToUndefined<T>;
